// And groups predicates with the AND operator between them.
func And(predicates ...predicate.MessageRecord) predicate.MessageRecord {
	return predicate.MessageRecord(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.MessageRecord) predicate.MessageRecord {
	return predicate.MessageRecord(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.MessageRecord) predicate.MessageRecord {
	return predicate.MessageRecord(sql.NotPredicates(p))
}
